```cpp
#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A)
{
    /* Parallelise the outer loop over the rows of C.  Each thread works
       on a distinct row i and performs all operations for that row,
       so the work is embarrassingly parallel. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        /* Pointers to the current row of C and A for faster access */
        double* c_row = C[i].data();
        const double* a_row = A[i].data();

        /* 1. Scale the lower triangular part of the row by beta */
        for (int j = 0; j <= i; ++j) {
            c_row[j] *= beta;
        }

        /* 2. Add the rank‑1 update C += alpha * A * Aᵀ */
        for (int k = 0; k < m; ++k) {
            const double aik = alpha * a_row[k];          // pre‑compute per k
            for (int j = 0; j <= i; ++j) {
                /* A[j][k] is accessed in the inner loop; accessing via
                   the original vector gives a contiguous read in j. */
                c_row[j] += aik * A[j][k];
            }
        }
    }
}
