```cpp
#include <cmath>
#include <vector>

void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
    // Use raw pointers to avoid bounds checking and increase cache locality.
    for (int i = 0; i < n; ++i) {
        double* row_i = A[i].data();        // pointer to the i‑th row
        // Process sub‑diagonal elements (j < i)
        for (int j = 0; j < i; ++j) {
            double* row_j   = A[j].data();  // pointer to the j‑th row
            double sum = 0.0;
            // k loop
            for (int k = 0; k < j; ++k) {
                sum += row_i[k] * row_j[k];
            }
            row_i[j] = (row_i[j] - sum) / row_j[j];
        }
        // Diagonal element (i == i)
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            sum += row_i[k] * row_i[k];
        }
        row_i[i] = std::sqrt(row_i[i] - sum);
    }
}
