#include <vector>
#include <cstddef>
#include <cstdint>
#include <immintrin.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    // We convert the 2‑D structure to a contiguous set of pointers
    // for maximal cache efficiency – the original row vectors are left
    // untouched so the function signature stays unchanged.
    // L[i] is already a std::vector<double> so we can use &L[i][0]
    // (the data is guaranteed contiguous in a single vector).
    const std::size_t *const __restrict row_ptrs[n];
    for (int i = 0; i < n; ++i)
        row_ptrs[i] = reinterpret_cast<const std::size_t *>(&L[i][0]);

    double *__restrict x_ptr = &x[0];
    const double *__restrict b_ptr = &b[0];

    for (int i = 0; i < n; ++i) {
        double sum = b_ptr[i];
        const double *restrict Li = reinterpret_cast<const double *>(row_ptrs[i]);

        // Unroll the inner loop for small i – the compiler will
        // keep the unrolled version only when it is profitable.
        int j = 0;
        int limit = i - (i & 3);
        for (; j < limit; j += 4) {
            sum -= Li[j]     * x_ptr[j];
            sum -= Li[j + 1] * x_ptr[j + 1];
            sum -= Li[j + 2] * x_ptr[j + 2];
            sum -= Li[j + 3] * x_ptr[j + 3];
        }
        for (; j < i; ++j)
            sum -= Li[j] * x_ptr[j];

        x_ptr[i] = sum / Li[i];
    }
}
