```cpp
#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

// Floyd‑Warshall with cache‑friendly layout and OpenMP parallelism.
// Function signature is unchanged; the behaviour (in‑place update) is preserved.
inline static void fw_kernel_omp(std::vector<int>& data, int n) {
    // Work on a contiguous flat array (row major).
    // OpenMP parallelise the outermost loop (over rows).
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        int *rowi = &data[i * n];
        for (int k = 0; k < n; ++k) {
            int aik = rowi[k];                 // path[i][k]
            if (aik == INT_MAX) continue;     // avoid overflow
            int *rowk = &data[k * n];
            for (int j = 0; j < n; ++j) {
                int alt = aik + rowk[j];
                if (alt < rowi[j]) rowi[j] = alt;
            }
        }
    }
}

void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Flatten the 2‑D vector to a 1‑D vector for efficient access.
    std::vector<int> flat(n * n);
    for (int i = 0; i < n; ++i)
        std::copy_n(path[i].begin(), n, flat.begin() + i * n);

    fw_kernel_omp(flat, n);

    // Copy the results back.
    for (int i = 0; i < n; ++i)
        std::copy_n(flat.begin() + i * n, n, path[i].begin());
}
