#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gesummv(int n,
                    double alpha,
                    double beta,
                    std::vector<std::vector<double>>& A,
                    std::vector<std::vector<double>>& B,
                    std::vector<double>& tmp,
                    std::vector<double>& x,
                    std::vector<double>& y)
{
    // Ensure input containers have the expected size
    // (the harness guarantees this, but adding assertions helps catch bugs)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sumA = 0.0;
        double sumB = 0.0;
        const double* arow = A[i].data();
        const double* brow = B[i].data();
        const double* xrow = x.data();          // same for all rows
        double* tmpRow = &tmp[i];
        double* yRow = &y[i];

        // Unroll the inner loop by a factor of 4 for modest SIMD friendliness
        int j = 0;
        #pragma SIMD
        for (; j <= n - 4; j += 4) {
            sumA += arow[j]     * xrow[j];
            sumA += arow[j + 1] * xrow[j + 1];
            sumA += arow[j + 2] * xrow[j + 2];
            sumA += arow[j + 3] * xrow[j + 3];

            sumB += brow[j]     * xrow[j];
            sumB += brow[j + 1] * xrow[j + 1];
            sumB += brow[j + 2] * xrow[j + 2];
            sumB += brow[j + 3] * xrow[j + 3];
        }
        // Remainder
        for (; j < n; ++j) {
            sumA += arow[j] * xrow[j];
            sumB += brow[j] * xrow[j];
        }

        *tmpRow = sumA;
        *yRow  = alpha * sumA + beta * sumB;
    }
}
