#include <vector>
#include <cstddef>
#include <omp.h>

/*  Kernel performs mean centering of a matrix (n samples × m variables)
 *  and computes the sample covariance matrix of the centered data.
 *
 *  Input:  data[n][m]   – 2‑D vector with row‑major layout
 *          cov[m][m]    – 2‑D vector where the covariance will be stored
 *          mean[m]      – 1‑D vector to store the means of the columns
 *
 *  All matrices are passed by reference and must already be sized
 *  appropriately.  The function returns the covariance matrix with
 *  full symmetry (cov[i][j] == cov[j][i]).
 */

void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean)
{
    /* ---------------------------------------------
     * 1. Compute column means (parallelised)
     * --------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i) {
            s += data[i][j];
        }
        mean[j] = s / n;
    }

    /* ---------------------------------------------
     * 2. Mean‑center the data in place (parallelised)
     * --------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();                // pointer to row
        for (int j = 0; j < m; ++j) {
            row[j] -= mean[j];
        }
    }

    /* ---------------------------------------------
     * 3. Compute upper‑triangular part of covariance
     *    all operations are vector‑sized.
     * --------------------------------------------- */
    const double denom = 1.0 / double(n - 1);       // pre‑compute reciprocal

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* cov_i = cov[i].data();             // pointer to row i
        for (int j = i; j < m; ++j) {
            double s = 0.0;
            for (int k = 0; k < n; ++k) {          // accumulate dot product
                s += data[k][i] * data[k][j];
            }
            double val = s * denom;
            cov_i[j] = val;
            cov[j][i] = val;                       // copy to symmetric element
        }
    }
}
