#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_jacobi_1d(int tsteps,
                      int n,
                      std::vector<double>& A,
                      std::vector<double>& B)
{
    double *const Ap = A.data();          // raw pointers to vector data
    double *const Bp = B.data();
    const double c = 1.0 / 3.0;           // constant coefficient

    /* Each time‑step is sequential because of data dependencies,
       but the spatial updates can be parallelised. */
    for (int t = 0; t < tsteps; ++t)
    {
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
            Bp[i] = c * (Ap[i - 1] + Ap[i] + Ap[i + 1]);

#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i)
            Ap[i] = c * (Bp[i - 1] + Bp[i] + Bp[i + 1]);
    }
}
