gramschmidt:
```cpp
#include <cmath>
#include <cstdlib>
#include <vector>
#include <omp.h>

/* Main computational kernel.
   QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/
   The interface must remain unchanged. */
void kernel_gramschmidt(int m, int n,
			std::vector<std::vector<double>>& A,
			std::vector<std::vector<double>>& R,
			std::vector<std::vector<double>>& Q) {

    /* Create flat views of the 2‑D vectors to avoid pointer chasing. */
    double *const A_flat = &A[0][0];
    double *const R_flat = &R[0][0];
    double *const Q_flat = &Q[0][0];

    const int stride = m;                       // column stride

    for (int k = 0; k < n; ++k) {
        /* 1) Compute norm of the k‑th column of A.              */
        double nrm = 0.0;
        for (int i = 0; i < m; ++i) {
            const double a = A_flat[i + k*stride];
            nrm += a * a;
        }
        const double rkk = std::sqrt(nrm);
        R_flat[k + k*stride] = rkk;

        /* 2) Normalise the k‑th column to form Q.                */
        for (int i = 0; i < m; ++i) {
            Q_flat[i + k*stride] = A_flat[i + k*stride] / rkk;
        }

        /* 3) Orthogonalise the remaining columns.  Parallelise over j. */
        #pragma omp parallel for schedule(static)
        for (int j = k + 1; j < n; ++j) {
            double rij = 0.0;
            /* Dot product Q[:,k] · A[:,j] */
            for (int i = 0; i < m; ++i) {
                rij += Q_flat[i + k*stride] * A_flat[i + j*stride];
            }
            R_flat[k + j*stride] = rij;

            /* Subtract the projection.  Use local pointer to avoid
               repeated array indexing. */
            double *A_col_j = A_flat + j*stride;
            double *Q_col_k = Q_flat + k*stride;
            for (int i = 0; i < m; ++i) {
                A_col_j[i] -= Q_col_k[i] * rij;
            }
        }
    }
}
