nussinov:
```cpp
#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

/* Optimised Nussinov kernel.
 *
 * The algorithm is rewritten to process the DP table along
 * increasing subsequence lengths (anti‑diagonals).  This ordering
 * removes data dependencies between iterations of the outer loop
 * and allows us to parallelise the work on each anti‑diagonal.
 * The code uses only integer arithmetic and a single pass
 * over the sequence for each anti‑diagonal.
 *
 * The original semantics are preserved: the contents of
 * `table[i][j]` after the function returns are identical to
 * those produced by the original, serial implementation.
 */

static constexpr int match(int b1, int b2) {
    // Agent: 0=A, 1=C, 2=G, 3=U (sum to 3 if complementary)
    return (b1 + b2 == 3) ? 1 : 0;
}

void kernel_nussinov(int n, std::vector<int> &seq,
                     std::vector<std::vector<int>> &table) {
    // All anti-diagonals (subsequence lengths) from 1 to n-1
    for (int len = 1; len < n; ++len) {
#pragma omp parallel for schedule(static)
        for (int i = 0; i + len < n; ++i) {
            int j = i + len;
            int best = table[i][j];          // initialise from previous work

            // Extend from the left
            if (j - 1 >= 0)
                best = std::max(best, table[i][j - 1]);

            // Extend from the right
            if (i + 1 < n)
                best = std::max(best, table[i + 1][j]);

            // Pairing i with j (or no pair if i == j-1)
            if (i < j - 1) {
                best = std::max(best, table[i + 1][j - 1] + match(seq[i], seq[j]));
            } else {
                best = std::max(best, table[i + 1][j - 1]); // one side empty
            }

            // Split the range [i..j] into two subranges
            for (int k = i + 1; k < j; ++k) {
                best = std::max(best, table[i][k] + table[k + 1][j]);
            }

            table[i][j] = best;
        }
    }
}
