```cpp
#include <vector>
#include <omp.h>
#include <cstring>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    // Flatten the 2-D vectors into 1-D contiguous arrays for faster access
    const size_t sizeC = static_cast<size_t>(n) * n;
    const size_t sizeAB = static_cast<size_t>(n) * m;

    double *c = new double[sizeC];
    double *a = new double[sizeAB];
    double *b = new double[sizeAB];

    // Copy data into contiguous arrays
    for (int i = 0; i < n; ++i) {
        std::memcpy(&c[i * n], &C[i][0], n * sizeof(double));
        std::memcpy(&a[i * m], &A[i][0], m * sizeof(double));
        std::memcpy(&b[i * m], &B[i][0], m * sizeof(double));
    }

    // Main loop – lower‑triangular block
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // scale the lower part of row i
        double *ci   = &c[i * n];
        double *aci  = &a[i * m];
        double *bci  = &b[i * m];
        for (int j = 0; j <= i; ++j) {
            ci[j] *= beta;
        }

        // compute the rank‑2 update for row i
        for (int k = 0; k < m; ++k) {
            double aik = a[i * m + k];      // A[i][k]
            double bkk = b[i * m + k];      // B[i][k]
            double aik_bggi = aik * alpha;  // precompute common factor
            double bkk_bggi = bkk * alpha;

            double *ak_column = &a[0 * m + k]; // column k of A
            double *bk_column = &b[0 * m + k]; // column k of B

            for (int j = 0; j <= i; ++j) {
                ci[j] += (ak_column[j] * bkk_bggi) + (bk_column[j] * aik_bggi);
            }
        }
    }

    // Copy results back to the original C matrix
    for (int i = 0; i < n; ++i) {
        std::memcpy(&C[i][0], &c[i * n], n * sizeof(double));
    }

    delete[] c;
    delete[] a;
    delete[] b;
}
