/* Main computational kernel. 
   The whole function will be timed, including the call and return. */
void kernel_mvt(int n,
                std::vector<double>& x1,
                std::vector<double>& x2,
                std::vector<double>& y_1,
                std::vector<double>& y_2,
                std::vector<std::vector<double>>& A) {
    // Parallel over the outer dimension – each thread works on independent rows.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum1 = 0.0;
        double sum2 = 0.0;

        // Unroll the inner loops slightly for extra performance.
        int j = 0;
        for (; j + 3 < n; j += 4) {
            sum1 += A[i][j]     * y_1[j];
            sum1 += A[i][j + 1] * y_1[j + 1];
            sum1 += A[i][j + 2] * y_1[j + 2];
            sum1 += A[i][j + 3] * y_1[j + 3];

            sum2 += A[j][i]     * y_2[j];
            sum2 += A[j + 1][i] * y_2[j + 1];
            sum2 += A[j + 2][i] * y_2[j + 2];
            sum2 += A[j + 3][i] * y_2[j + 3];
        }
        for (; j < n; ++j) {
            sum1 += A[i][j] * y_1[j];
            sum2 += A[j][i] * y_2[j];
        }

        // Add the computed sums to the original vector elements.
        x1[i] += sum1;
        x2[i] += sum2;
    }
}
