    for (int i = 0; i < n; ++i) y[i] = 0.0;
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) tmp[i] = 0.0;

    // thread‑local accumulators for y
    const int num_threads = omp_get_max_threads();
    std::vector<std::vector<double>> local_y(num_threads, std::vector<double>(n, 0.0));

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto& y_local = local_y[tid];

        #pragma omp for schedule(static)
        for (int i = 0; i < m; ++i) {
            double dot = 0.0;
            const auto& Ai = A[i];
            for (int j = 0; j < n; ++j)
                dot += Ai[j] * x[j];
            tmp[i] = dot;

            for (int j = 0; j < n; ++j)
                y_local[j] += Ai[j] * dot;
        }
    }

    // combine thread local y into the final y
    for (int t = 0; t < num_threads; ++t) {
        const auto& y_local = local_y[t];
        for (int j = 0; j < n; ++j)
            y[j] += y_local[j];
    }
}
