// Optimised version of kernel_jacobi_2d
#include <vector>
#include <cstddef>
#include <omp.h>

/* Main computational kernel.
 * The entire function (including call and return) will be timed. */
void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B) {

    // Flatten the 2‑D vectors into 1‑D for cache friendliness
    const std::size_t N = static_cast<std::size_t>(n);
    const std::size_t stride = N;
    const std::size_t total = N * N;

    std::vector<double> a(total), b(total);
    for (std::size_t i = 0; i < total; ++i) {
        a[i] = A[i / N][i % N];
        b[i] = B[i / N][i % N];
    }

    const double coeff = 0.2;
    const int inner_start = 1;
    const int inner_end   = n - 2;            // inclusive

    // Main time‑stepping loop
    for (int t = 0; t < tsteps; ++t) {
        // First update: B[i][j] = coeff * sum of A's neighbours
        #pragma omp parallel for schedule(static)
        for (int i = inner_start; i <= inner_end; ++i) {
            const std::size_t row = static_cast<std::size_t>(i) * stride;
            for (int j = inner_start; j <= inner_end; ++j) {
                const std::size_t idx = row + j;
                b[idx] = coeff * ( a[idx]
                                 + a[idx - 1]          // same row, previous column
                                 + a[idx + 1]          // same row, next column
                                 + a[idx + stride]     // next row, same column
                                 + a[idx - stride] );  // previous row, same column
            }
        }

        // Second update: A[i][j] = coeff * sum of B's neighbours
        #pragma omp parallel for schedule(static)
        for (int i = inner_start; i <= inner_end; ++i) {
            const std::size_t row = static_cast<std::size_t>(i) * stride;
            for (int j = inner_start; j <= inner_end; ++j) {
                const std::size_t idx = row + j;
                a[idx] = coeff * ( b[idx]
                                 + b[idx - 1]
                                 + b[idx + 1]
                                 + b[idx + stride]
                                 + b[idx - stride] );
            }
        }
    }

    // Copy back to the original 2‑D vectors (preserving exact values)
    for (std::size_t i = 0; i < total; ++i) {
        A[i / N][i % N] = a[i];
        B[i / N][i % N] = b[i];
    }
}
