/* Main computational kernel. The whole function will be timed,
   including the call and return.  */
void kernel_lu(int n,
               std::vector<std::vector<double>>& A) {
    // Parallelise across the outer dimension only at the start of each row,
    // because each row depends on all previous rows.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Cache pointers to the current row and to the temporary variables.
        double* Ai = A[i].data();

        /* --- Compute the L part (j < i) -------------------------------- */
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            double* Ak  = Ai;          // A[i][k] (initially all zeros)
            double* Akj = A[j].data(); // A[k][j]
            // Unroll the k loop in small chunks for speed.
            int k = 0;
            for (; k + 3 < j; k += 4) {
                sum += Ai[k]     * Akj[k];
                sum += Ai[k + 1] * Akj[k + 1];
                sum += Ai[k + 2] * Akj[k + 2];
                sum += Ai[k + 3] * Akj[k + 3];
            }
            for (; k < j; ++k) {
                sum += Ai[k] * Akj[k];
            }
            Ai[j] = (Ai[j] - sum) / A[j][j];
        }

        /* --- Compute the U part (j >= i) -------------------------------- */
        // The updates of different U columns are independent; we can
        // parallelise this part across j.
        #pragma omp parallel for schedule(static)
        for (int j = i; j < n; ++j) {
            double sum = 0.0;
            double* Ai  = A[i].data();
            // For U columns the inner sum runs over k = 0..i-1
            for (int k = 0; k < i; ++k) {
                sum += Ai[k] * A[k][j];
            }
            A[i][j] -= sum;
        }
    }
}
