    for (int i = 0; i < m; ++i) s[i] = 0.0;
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) q[i] = 0.0;

    /* Compute q and accumulate contributions to s in two loops.
       The outer loop is parallelised over the rows of A (n). */
#pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double ri = r[i];
        double qi = 0.0;
        for (int j = 0; j < m; ++j) {
            double aij = A[i][j];
            /* Update s[j] atomically (needed because many rows write
               to the same slot). */
            #pragma omp atomic
            s[j] += ri * aij;
            qi += aij + p[j];
        }
        q[i] = qi;
    }
}
