/* Matrix‑multiply kernel with single–buffer temp and blocking.
   The outer two loops are parallelized with OpenMP. The kernel
   keeps the original semantics (row–major indexing) while
   exploiting spatial locality and SIMD capability. */
void kernel_2mm(int ni, int nj, int nk, int nl,
                double alpha, double beta,
                std::vector<std::vector<double>>& tmp,
                std::vector<std::vector<double>>& A,
                std::vector<std::vector<double>>& B,
                std::vector<std::vector<double>>& C,
                std::vector<std::vector<double>>& D)
{
    /* Block size tuned for typical cache sizes. */
    constexpr std::size_t Bs = 64;     // inner block size
    constexpr std::size_t Bt = 32;     // outer block size

    /* 1. compute tmp = alpha * A * B  (GiB (ij) = α∑k A(ik)B(kj)) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ii = 0; ii < ni; ii += Bt) {
        for (int jj = 0; jj < nj; jj += Bt) {
            int iend = std::min(ii + Bt, ni);
            int jend = std::min(jj + Bt, nj);
            for (int i = ii; i < iend; ++i) {
                for (int j = jj; j < jend; ++j) {
                    double sum = 0.0;
                    int kend = nk;
                    for (int k = 0; k < kend; k += Bs) {
                        int kend2 = std::min(k + Bs, kend);
                        for (int kk = k; kk < kend2; ++kk)
                            sum += alpha * at(A, i, kk) * at(B, kk, j);
                    }
                    at(tmp, i, j) = sum;
                }
            }
        }
    }

    /* 2. compute D = beta * D + tmp * C  (D(ij) = β D(ij) + ∑k tmp(ik) C(kj)) */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int ii = 0; ii < ni; ii += Bt) {
        for (int jj = 0; jj < nl; jj += Bt) {
            int iend = std::min(ii + Bt, ni);
            int jend = std::min(jj + Bt, nl);
            for (int i = ii; i < iend; ++i) {
                for (int j = jj; j < jend; ++j) {
                    double sum = beta * at(D, i, j);
                    int kend = nj;
                    for (int k = 0; k < kend; k += Bs) {
                        int kend2 = std::min(k + Bs, kend);
                        for (int kk = k; kk < kend2; ++kk)
                            sum += at(tmp, i, kk) * at(C, kk, j);
                    }
                    at(D, i, j) = sum;
                }
            }
        }
    }
