#include <vector>
#include <omp.h>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z) {

    /* --------------------------------------------------------------
       1. A[i][j] = A[i][j] + u1[i] * v1[j] + u2[i] * v2[j]
       --------------------------------------------------------------*/
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        const double ui1 = u1[i];
        const double ui2 = u2[i];
        double* Ai = A[i].data();          // pointer to row i
        for (int j = 0; j < n; ++j) {
            Ai[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    /* --------------------------------------------------------------
       2. x[i] = x[i] + beta * A[j][i] * y[j]  (outer loop over i)
       --------------------------------------------------------------*/
    // Note: The expression accesses A[j][i], so we need to iterate over i
    // with a shared outer loop and a parallel inner loop over j.
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double xi = x[i];
        const double bi = beta;
        double* yi = y.data();                 // to avoid repeated indexing
        for (int j = 0; j < n; ++j) {
            xi += bi * A[j][i] * yi[j];
        }
        x[i] = xi;
    }

    /* --------------------------------------------------------------
       3. x[i] = x[i] + z[i]
       --------------------------------------------------------------*/
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* --------------------------------------------------------------
       4. w[i] = w[i] + alpha * A[i][j] * x[j]
       --------------------------------------------------------------*/
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        const double ai = alpha;
        double* Ai = A[i].data();          // pointer to row i
        double wi = w[i];
        const double* x_arr = x.data();    // pointer to x
        for (int j = 0; j < n; ++j) {
            wi += ai * Ai[j] * x_arr[j];
        }
        w[i] = wi;
    }
}
