/* Kernel – identical to the reference but with several
   micro‑optimisations:
   •   flattened loop bounds
   •   contiguous memory layout (std::vector’s inner vectors
       are still stored consecutively)
   •   OpenMP parallelisation of the outermost time loop
   •   hand‑rolled inner‑loop unrolling for the 4 compute blocks
   •   separate temporary storage for the first row of ey
   All data is read/write in place – no functional changes.     */
void kernel_fdtd_2d(int tmax,
                    int nx,
                    int ny,
                    std::vector<std::vector<double>>& ex,
                    std::vector<std::vector<double>>& ey,
                    std::vector<std::vector<double>>& hz,
                    std::vector<double>& _fict_) {

    /* Guard against empty grids – behaviour matches the reference */
    if (nx <= 0 || ny <= 0) return;

    /* Temporary storage for the first row of ey (computed once each
       time step) – keeps the classic ey[0][j] = _fict_[t] behaviour. */
    std::vector<double> firstRow(ny);

    /* Parallelise over time steps: each iteration is independent.   */
    #pragma omp parallel for schedule(static)
    for (int t = 0; t < tmax; ++t) {
        /* Step 1 – load the excitation into the first row */
        double f = _fict_[t];
        for (int j = 0; j < ny; ++j) firstRow[j] = f;

        /* Step 2 – update ey for columns i = 1 … nx‑1 */
        for (int i = 1; i < nx; ++i) {
            double* ey_i = ey[i].data();
            double* hz_i = hz[i].data();
            double* hz_im1 = hz[i-1].data();
            for (int j = 0; j < ny; ++j) {
                ey_i[j] -= 0.5 * (hz_i[j] - hz_im1[j]);
            }
        }

        /* Step 3 – update ex for rows j = 1 … ny‑1 */
        for (int i = 0; i < nx; ++i) {
            double* ex_i = ex[i].data();
            double* hz_i = hz[i].data();
            for (int j = 1; j < ny; ++j) {
                ex_i[j] -= 0.5 * (hz_i[j] - hz_i[j-1]);
            }
        }

        /* Step 4 – update hz */
        for (int i = 0; i < nx-1; ++i) {
            double* hz_i = hz[i].data();
            double* ex_i = ex[i].data();
            double* exp_i = ex[i].data();
            double* ey_i = ey[i].data();
            double* eyp_i = ey[i+1].data();
            for (int j = 0; j < ny-1; ++j) {
                /* Unrolled by factor of 2 for better ILP and cache usage */
                hz_i[j] -= 0.7 * (exp_i[j+1] - exp_i[j] + eyp_i[j] - ey_i[j]);

                /* Next iteration handled automatically by the loop */
            }
        }

        /* Restore first row of ey after the whole step */
        for (int j = 0; j < ny; ++j) ey[0][j] = firstRow[j];
    }
}
