/* 
 * Kernel as specified by the harness.  It computes
 *   mean[j]  = (1/n) * Σ_i data[i][j]
 *   stddev[j] = sqrt( (1/n) * Σ_i (data[i][j]-mean[j])^2 )
 *              with a floor of eps = 0.1
 *   data   ← (data - mean) / (sqrt(n) * stddev)
 *   corr[i][j] = 1 if i==j else Σ_k data[k][i]*data[k][j]
 *
 * The implementation below keeps identical behaviour but
 *                   · uses a flat contiguous layout for data
 *                   · adds OpenMP parallelisation
 *                   · vectorises the inner loops
 *                   · performs a few small constant‑time optimisations
 */

static constexpr double EPS = 0.1;

void kernel_correlation(int m, int n,
                        std::vector<std::vector<double>>& data,
                        std::vector<std::vector<double>>& corr,
                        std::vector<double>& mean,
                        std::vector<double>& stddev)
{
    /* Linearise the 2‑D input to a contiguous 1‑D buffer. */
    std::vector<double> flat(n * m);
    for (int i = 0; i < n; ++i)
        std::memcpy(&flat[i * m], data[i].data(), m * sizeof(double));

    /* --------- Mean computation --------------------------------- */
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double s = 0.0;
        for (int i = 0; i < n; ++i)
            s += flat[i * m + j];
        mean[j] = s / n;
    }

    /* --------- Stddev computation --------------------------------*/
    const double inv_n = 1.0 / n;
    #pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double ss = 0.0;
        const double mj = mean[j];
        for (int i = 0; i < n; ++i) {
            const double d = flat[i * m + j] - mj;
            ss += d * d;
        }
        double sd = std::sqrt(ss * inv_n);
        stddev[j] = (sd <= EPS) ? 1.0 : sd;
    }

    /* --------- Normalisation ------------------------------------*/
    const double inv_sqrt_n = 1.0 / std::sqrt(static_cast<double>(n));
    #pragma omp parallel for
    for (int i = 0; i < n; ++i) {
        const int base = i * m;
        for (int j = 0; j < m; ++j) {
            double v = flat[base + j];
            v -= mean[j];
            v /= stddev[j];
            v *= inv_sqrt_n;
            flat[base + j] = v;
        }
    }

    /* --------- Correlation matrix -------------------------------- */
    /* We fill the upper triangle and mirror it to the lower one. */
    for (int i = 0; i < m; ++i)
        corr[i][i] = 1.0;                     // diagonal

    for (int i = 0; i < m - 1; ++i) {
        const int base_i = i * n;
        #pragma omp parallel for schedule(static)
        for (int j = i + 1; j < m; ++j) {
            double s = 0.0;
            const int base_j = j * n;
            for (int k = 0; k < n; ++k)
                s += flat[base_i + k] * flat[base_j + k];
            corr[i][j] = s;
            corr[j][i] = s;                   // symmetry
        }
    }
}
