/* Helper to convert 2‑D std::vector to a contiguous flat array
   for better cache locality. The layout is row major. */
static inline double* flat(std::vector<std::vector<double>>& M, int rows, int cols) {
    double* p = new double[rows * cols];
    for (int i = 0; i < rows; ++i)
        std::copy(M[i].data(), M[i].data() + cols, p + i * cols);
    return p;
}

/* Write back flat data into a 2‑D std::vector */
static inline void reshape(double* p, std::vector<std::vector<double>>& M,
                           int rows, int cols) {
    for (int i = 0; i < rows; ++i)
        std::copy(p + i * cols, p + (i + 1) * cols, M[i].begin());
}

/* Blocked matrix‑multiplication with loop interchange and
   OpenMP parallelism.  All loops are in the same order as the
   original 3MM but are rearranged for better cache usage. */
static inline void gemm(int M, int N, int K,
                        const double* A, const double* B, double* C,
                        int lda, int ldb, int ldc) {
    const int BS = 64;               // block size
#pragma omp parallel for schedule(static)
    for (int ii = 0; ii < M; ii += BS) {
        int imax = std::min(ii + BS, M);
        for (int kk = 0; kk < K; kk += BS) {
            int kmax = std::min(kk + BS, K);
            for (int jj = 0; jj < N; jj += BS) {
                int jmax = std::min(jj + BS, N);
                for (int i = ii; i < imax; ++i) {
                    const double* aRow = A + i * lda;
                    double* cRow = C + i * ldc;
                    for (int k = kk; k < kmax; ++k) {
                        double aik = aRow[k];
                        const double* bCol = B + k * ldb;
                        for (int j = jj; j < jmax; ++j)
                            cRow[j] += aik * bCol[j];
                    }
                }
            }
        }
    }
}

void kernel_3mm(int ni, int nj, int nk, int nl, int nm,
		std::vector<std::vector<double>>& E,
		std::vector<std::vector<double>>& A,
		std::vector<std::vector<double>>& B,
		std::vector<std::vector<double>>& F,
		std::vector<std::vector<double>>& C,
		std::vector<std::vector<double>>& D,
		std::vector<std::vector<double>>& G) {

    /* Allocate flat arrays for input data */
    double* flatA = flat(A, ni, nk);
    double* flatB = flat(B, nk, nj);
    double* flatC = flat(C, nj, nm);
    double* flatD = flat(D, nm, nl);

    /* Allocate flat result arrays */
    double* flatE = new double[ni * nj]{0};
    double* flatF = new double[nj * nl]{0};
    double* flatG = new double[ni * nl]{0};

    /* E = A*B */
    gemm(ni, nj, nk, flatA, flatB, flatE, nk, nk, nj);

    /* F = C*D */
    gemm(nj, nl, nm, flatC, flatD, flatF, nm, nm, nl);

    /* G = E*F */
    gemm(ni, nl, nj, flatE, flatF, flatG, nj, nj, nl);

    /* Write back results */
    reshape(flatE, E, ni, nj);
    reshape(flatF, F, nj, nl);
    reshape(flatG, G, ni, nl);

    /* Clean up */
    delete[] flatA;
    delete[] flatB;
    delete[] flatC;
    delete[] flatD;
    delete[] flatE;
    delete[] flatF;
    delete[] flatG;
}
