    std::size_t N = src.size();
    std::vector<double> flat(N * N * N);
    for (std::size_t i = 0; i < N; ++i)
        for (std::size_t j = 0; j < N; ++j)
            for (std::size_t k = 0; k < N; ++k)
                flat[(i * N + j) * N + k] = src[i][j][k];
    return flat;
}

/* Convert back from flat to nested vectors (keeping the original layout) */
inline void unflatten(const std::vector<double>& flat,
                      std::vector<std::vector<std::vector<double>>>& dst) {
    std::size_t N = dst.size();
    for (std::size_t i = 0; i < N; ++i)
        for (std::size_t j = 0; j < N; ++j)
            for (std::size_t k = 0; k < N; ++k)
                dst[i][j][k] = flat[(i * N + j) * N + k];
}

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B) {
    const std::size_t N = static_cast<std::size_t>(n);
    std::vector<double> a = flatten(A);
    std::vector<double> b = flatten(B);

    const double coef = 0.125;        // 1/8

    #pragma omp parallel for collapse(3) schedule(static)
    for (int t = 1; t <= tsteps; ++t) {
        /* First sweep: A -> B */
        for (std::size_t i = 1; i < N - 1; ++i)
            for (std::size_t j = 1; j < N - 1; ++j)
                for (std::size_t k = 1; k < N - 1; ++k) {
                    double centre = cell(a, i, j, k, N);
                    double sum = (cell(a, i + 1, j, k, N) - 2.0 * centre + cell(a, i - 1, j, k, N))
                               + (cell(a, i, j + 1, k, N) - 2.0 * centre + cell(a, i, j - 1, k, N))
                               + (cell(a, i, j, k + 1, N) - 2.0 * centre + cell(a, i, j, k - 1, N));
                    cell(b, i, j, k, N) = coef * sum + centre;
                }

        /* Second sweep: B -> A */
        for (std::size_t i = 1; i < N - 1; ++i)
            for (std::size_t j = 1; j < N - 1; ++j)
                for (std::size_t k = 1; k < N - 1; ++k) {
                    double centre = cell(b, i, j, k, N);
                    double sum = (cell(b, i + 1, j, k, N) - 2.0 * centre + cell(b, i - 1, j, k, N))
                               + (cell(b, i, j + 1, k, N) - 2.0 * centre + cell(b, i, j - 1, k, N))
                               + (cell(b, i, j, k + 1, N) - 2.0 * centre + cell(b, i, j, k - 1, N));
                    cell(a, i, j, k, N) = coef * sum + centre;
                }
    }

    /* Write back results */
    unflatten(a, A);
    unflatten(b, B);
}
