#include <vector>
#include <algorithm>
#include <cstddef>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    /* 
       1. Transform the 2‑D std::vector layout to a single flat buffer
          to enable pointer arithmetic and a true cache‑friendly access
          pattern.  The original code uses row‑major layout so we
          flatten exactly in that order.
       2. Use OpenMP parallelism on the outermost i‑loop and on the
          beta‑rescaling loop to keep the thread count optimal.
       3. Introduce a classic cache‑blocking (tiling) on the j‑dimension
          to increase temporal locality for B and C.
       4. Use SIMD hints via the `restrict` keyword (via compiler
          attributes) and loop‑unrolling for the inner product.
    */

    // ------------------------------------------------------------------
    // Step 1 : Flatten the matrices into row‑major buffers
    // ------------------------------------------------------------------
    const size_t lenA = static_cast<size_t>(ni) * nk;
    const size_t lenB = static_cast<size_t>(nk) * nj;
    const size_t lenC = static_cast<size_t>(ni) * nj;

    std::vector<double> A_flat(lenA);
    std::vector<double> B_flat(lenB);
    std::vector<double> C_flat(lenC);

    for (int i = 0; i < ni; ++i) {
        std::copy(A[i].begin(), A[i].end(), &A_flat[static_cast<size_t>(i) * nk]);
    }
    for (int k = 0; k < nk; ++k) {
        std::copy(B[k].begin(), B[k].end(), &B_flat[static_cast<size_t>(k) * nj]);
    }
    for (int i = 0; i < ni; ++i) {
        std::copy(C[i].begin(), C[i].end(), &C_flat[static_cast<size_t>(i) * nj]);
    }

    // ------------------------------------------------------------------
    // Step 2 : Parameterized cache blocking (tile size = 64)
    // ------------------------------------------------------------------
    constexpr int tileJ = 64; // typical L1 cache line count for matrix vector
    constexpr int b = 4;      // unroll factor for inner j‑loop

    // =========================================================================
    // Parallel outermost loop over i
    // =========================================================================
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double* c_row = &C_flat[static_cast<size_t>(i) * nj];
        const double* a_row = &A_flat[static_cast<size_t>(i) * nk];

        // Beta scaling of C[i][j]
        if (beta == 0.0) {
            std::fill_n(c_row, nj, 0.0);
        } else if (beta != 1.0) {
            for (int j = 0; j < nj; ++j) c_row[j] *= beta;
        }

        // Main matrix product with cache blocking
        for (int jj = 0; jj < nj; jj += tileJ) {
            int j_block = std::min(tileJ, nj - jj);
            for (int k = 0; k < nk; ++k) {
                double aik = alpha * a_row[k];
                const double* b_row = &B_flat[static_cast<size_t>(k) * nj];
                int j = jj;
                // Unroll by 4
                for (; j <= jj + j_block - b; j += b) {
                    c_row[j]     += aik * b_row[j];
                    c_row[j + 1] += aik * b_row[j + 1];
                    c_row[j + 2] += aik * b_row[j + 2];
                    c_row[j + 3] += aik * b_row[j + 3];
                }
                // Remainder
                for (; j < jj + j_block; ++j) {
                    c_row[j] += aik * b_row[j];
                }
            }
        }
    }

    // ------------------------------------------------------------------
    // Step 3 : Copy back to the original C vector of vectors
    // ------------------------------------------------------------------
    for (int i = 0; i < ni; ++i) {
        std::copy(&C_flat[static_cast<size_t>(i) * nj], &C_flat[static_cast<size_t>(i) * nj] + nj,
                  C[i].begin());
    }
}
