/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& /*sum*/) {

    /* Parallelise over the (r, q) pairs – each pair is independent.
       The inner work is small, so a static schedule is adequate. */
#pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r) {
        for (int q = 0; q < nq; ++q) {
            /* A[r][q] is a row of length np – treat it as a contiguous
               C array to avoid bounds checks. */
            double* const a_row = &A[r][q][0];

            /* Allocate a temporary accumulator on the stack.  If np
               is small, alloca will be efficient and avoid dynamic
               allocation overhead. */
            double* sum = (double*)alloca(np * sizeof(double));
            std::memset(sum, 0, np * sizeof(double));

            for (int s = 0; s < np; ++s) {
                double* const c_row = &C4[s][0];          // row of C4
                const double a = a_row[s];                // element of A
                /* Unroll the inner p‑loop by a factor of 4 where possible
                   to aid the compiler's vectoriser. */
                int p = 0;
                for (; p + 3 < np; p += 4) {
                    sum[p]   += a * c_row[p];
                    sum[p+1] += a * c_row[p+1];
                    sum[p+2] += a * c_row[p+2];
                    sum[p+3] += a * c_row[p+3];
                }
                for (; p < np; ++p) sum[p] += a * c_row[p];
            }

            /* Write the accumulated values back into A[r][q]. */
            for (int p = 0; p < np; ++p) a_row[p] = sum[p];
        }
    }
}
