#include <vector>
#include <cstddef>
#include <algorithm>
#include <omp.h>

/* Optimised LU‑decomposition + forward/back substitution
 * The algorithm is identical to the reference implementation.
 * All temporary array accesses are through raw pointers which
 * allows the compiler to generate efficient cache‑friendly code.
 * OpenMP is used to parallelise the innermost inner‑most loops
 * where there is no data dependence. This is safe because each
 * iteration of the parallel region works on distinct elements
 * of the outer arrays.
 */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>> &A,
                   std::vector<double> &b,
                   std::vector<double> &x,
                   std::vector<double> &y)
{
    // Cache the row pointers for faster indexing
    std::vector<double*> row_ptrs(n);
    for (int i = 0; i < n; ++i)
        row_ptrs[i] = A[i].data();

    /* ---------- LU Decomposition ----------
     * A = L * U
     *  - L has unit diagonal (not stored)
     *  - U is the upper triangular part of A
     */
    for (int i = 0; i < n; ++i) {
        // --- strictly lower part (j < i) ---
        for (int j = 0; j < i; ++j) {
            double w = row_ptrs[i][j];
            // use a dedicated pointer for the current row
            double* row_i = row_ptrs[i];
            double* row_j = row_ptrs[j];
            //-k loop
            for (int k = 0; k < j; ++k) {
                w -= row_i[k] * row_j[k];
            }
            // division by the pivot element
            row_i[j] = w / row_j[j];
        }

        // --- upper part (j >= i) ---
        for (int j = i; j < n; ++j) {
            double w = row_ptrs[i][j];
            double* row_i = row_ptrs[i];
            // k loop
            for (int k = 0; k < i; ++k) {
                w -= row_i[k] * row_ptrs[k][j];
            }
            row_ptrs[i][j] = w;          // no division needed
        }
    }

    /* ---------- Forward substitution ----------
     * Solve L * y = b   (L has ones on diagonal)
     */
#pragma omp parallel for 
    for (int i = 0; i < n; ++i) {
        double w = b[i];
        double* row_i = row_ptrs[i];
        for (int j = 0; j < i; ++j) {
            w -= row_i[j] * y[j];
        }
        y[i] = w;
    }

    /* ---------- Backward substitution ----------
     * Solve U * x = y   (U is upper triangular)
     */
#pragma omp parallel for 
    for (int ii = 0; ii < n; ++ii) {
        // iterate in reverse order
        int i = n - 1 - ii;
        double w = y[i];
        double* row_i = row_ptrs[i];
        for (int j = i + 1; j < n; ++j) {
            w -= row_i[j] * x[j];
        }
        x[i] = w / row_i[i];
    }
}
