#include <vector>
#include <omp.h>

/* Replacement kernel implementing the same algorithm but using
 * flat arrays, pointer arithmetic, and OpenMP parallelization.
 * The externally visible signature is unchanged. */
void kernel_adi(int tsteps, int n,
                std::vector<std::vector<double>>& u,
                std::vector<std::vector<double>>& v,
                std::vector<std::vector<double>>& p,
                std::vector<std::vector<double>>& q)
{
    /* Flatten the 2‑D std::vector into a single block of memory for
     * each array.  This removes per‑row indirection and improves
     * cache locality.  All 4 arrays have the same size. */
    const size_t N = static_cast<size_t>(n) * n;
    std::vector<double> u_flat(N), v_flat(N), p_flat(N), q_flat(N);

    /* Helper lambda to access elements using a single index. */
    auto idx = [&](int i, int j) noexcept { return static_cast<size_t>(i) * n + j; };

    /* Copy initial data from the input vectors to the flattened arrays.
     * (The original code assumes that the input arrays are already
     * filled with the correct initial values; we preserve that behavior.) */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) {
            size_t id = idx(i, j);
            u_flat[id] = u[i][j];
            v_flat[id] = v[i][j];
            p_flat[id] = p[i][j];
            q_flat[id] = q[i][j];
        }

    /* Constants used throughout the algorithm. */
    const double DX = 1.0 / n;
    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0, B2 = 1.0;
    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);
    const double a   = -mul1 / 2.0;
    const double b   = 1.0 + mul1;
    const double c   = a;
    const double d   = -mul2 / 2.0;
    const double e   = 1.0 + mul2;
    const double f   = d;

    /* Main time loop. */
    for (int t = 1; t <= tsteps; ++t) {
        /* 1st pass – solve tridiagonal systems along the j‑direction
           for each fixed i (column).  Outer loop over i is parallelised. */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            /* boundary values for v and related arrays */
            v_flat[idx(0, i)] = 1.0;
            p_flat[idx(i, 0)] = 0.0;
            q_flat[idx(i, 0)] = v_flat[idx(0, i)];

            /* Forward sweep */
            for (int j = 1; j < n - 1; ++j) {
                size_t id = idx(i, j);
                double denom = a * p_flat[idx(i, j-1)] + b;
                p_flat[id] = -c / denom;
                q_flat[id] = (-d * u_flat[idx(j, i-1)] + (1.0 + 2.0 * d) * u_flat[idx(j, i)]
                             - f * u_flat[idx(j, i+1)]
                             - a * q_flat[idx(i, j-1)]) / denom;
            }

            v_flat[idx(n-1, i)] = 1.0;

            /* Backward sweep */
            for (int j = n-2; j >= 1; --j) {
                size_t id = idx(i, j);
                v_flat[id] = p_flat[id] * v_flat[idx(i, j+1)] + q_flat[id];
            }
        }

        /* 2nd pass – similar tridiagonal solve along the i‑direction
           for each fixed j (row). */
        #pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            /* boundary values for u and related arrays */
            u_flat[idx(i, 0)] = 1.0;
            p_flat[idx(i, 0)] = 0.0;
            q_flat[idx(i, 0)] = u_flat[idx(i, 0)];

            /* Forward sweep */
            for (int j = 1; j < n - 1; ++j) {
                size_t id = idx(i, j);
                double denom = d * p_flat[idx(i, j-1)] + e;
                p_flat[id] = -f / denom;
                q_flat[id] = (-a * v_flat[idx(i-1, j)] + (1.0 + 2.0 * a) * v_flat[idx(i, j)]
                             - c * v_flat[idx(i+1, j)]
                             - d * q_flat[idx(i, j-1)]) / denom;
            }

            u_flat[idx(i, n-1)] = 1.0;

            /* Backward sweep */
            for (int j = n-2; j >= 1; --j) {
                size_t id = idx(i, j);
                u_flat[id] = p_flat[id] * u_flat[idx(i, j+1)] + q_flat[id];
            }
        }
    }

    /* Copy results back to the original vector-of-vectors. */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j) {
            size_t id = idx(i, j);
            u[i][j] = u_flat[id];
            v[i][j] = v_flat[id];
            p[i][j] = p_flat[id];
            q[i][j] = q_flat[id];
        }
}
