#include <cmath>
#include <vector>
#include <omp.h>

/*
 * Optimised derivative filter kernel
 * The function signature must match the harness.
 * The implementation uses contiguous 1‑D arrays and OpenMP parallelism
 * to maximise CPU utilisation on modern x86‑64 with 8 threads.
 */
void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    // Flatten the 2‑D std::vector to 1‑D C array pointers
    const int N = w*h;
    float *in  = new float[N];
    float *out = new float[N];
    float *Y1  = new float[N];
    float *Y2  = new float[N];

    // ----- copy into contiguous buffers ---------------------------------
    for (int i = 0; i < w; ++i)
        std::memcpy(in  + i*h, imgIn[i].data(),  h*sizeof(float));
    for (int i = 0; i < w; ++i)
        std::memcpy(Y1 + i*h, y1  [i].data(),  h*sizeof(float));
    for (int i = 0; i < w; ++i)
        std::memcpy(Y2 + i*h, y2  [i].data(),  h*sizeof(float));
    for (int i = 0; i < w; ++i)
        std::memcpy(out + i*h, imgOut[i].data(), h*sizeof(float));

    // ----- pre‑compute constants -----------------------------------------
    const float exp_alpha  = std::exp(-float(alpha));
    const float exp_2alpha = std::exp(-2.0f*float(alpha));

    const float k = 1.0f - exp_alpha*(1.0f-exp_alpha) /
                        (1.0f + 2.0f*float(alpha)*exp_alpha - exp_2alpha);

    const float a1 =  k;
    const float a5 =  k;
    const float a2 =  k*exp_alpha*(float(alpha)-1.0f);
    const float a6 =  k*exp_alpha*(float(alpha)-1.0f);
    const float a3 =  k*exp_alpha*(float(alpha)+1.0f);
    const float a7 =  k*exp_alpha*(float(alpha)+1.0f);
    const float a4 = -k*exp_2alpha;
    const float a8 = -k*exp_2alpha;

    const float b1 = std::pow(2.0f, -float(alpha));
    const float b2 = -exp_2alpha;

    const float c1 = 1.0f;   // unchanged, kept for clarity
    const float c2 = 1.0f;   // unchanged, kept for clarity

    // ----- forward filtering across rows --------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        for (int j = 0; j < h; ++j) {
            const float img = in[i*h + j];
            const float y  = a1*img + a2*xm1 + b1*ym1 + b2*ym2;
            Y1[i*h + j] = y;
            xm1 = img;  ym2 = ym1;  ym1 = y;
        }
    }

    // ----- backward filtering across rows --------------------------------
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        for (int jj = h-1; jj >= 0; --jj) {
            const float y  = a3*xp1 + a4*xp2 + b1*yp1 + b2*yp2;
            Y2[i*h + jj] = y;
            xp2 = xp1; xp1 = in[i*h + jj];
            yp2 = yp1; yp1 = y;
        }
    }

    // ----- combine forward/backward results -----------------------------
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            out[i*h + j] = c1 * (Y1[i*h + j] + Y2[i*h + j]);

    // ----- forward filtering across columns (from imgOut) ---------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float img = out[i*h + j];
            const float y  = a5*img + a6*tm1 + b1*ym1 + b2*ym2;
            Y1[i*h + j] = y;
            tm1 = img;  ym2 = ym1;  ym1 = y;
        }
    }

    // ----- backward filtering across columns -----------------------------
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int ii = w-1; ii >= 0; --ii) {
            const float y  = a7*tp1 + a8*tp2 + b1*yp1 + b2*yp2;
            Y2[ii*h + j] = y;
            tp2 = tp1; tp1 = out[ii*h + j];
            yp2 = yp1; yp1 = y;
        }
    }

    // ----- final combination ---------------------------------------------
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            out[i*h + j] = c2 * (Y1[i*h + j] + Y2[i*h + j]);

    // ----- copy back to original 2-D vectors -----------------------------
    for (int i = 0; i < w; ++i)
        std::memcpy(imgOut[i].data(), out + i*h, h*sizeof(float));
    for (int i = 0; i < w; ++i)
        std::memcpy(y1[i].data(),    Y1 + i*h, h*sizeof(float));
    for (int i = 0; i < w; ++i)
        std::memcpy(y2[i].data(),    Y2 + i*h, h*sizeof(float));

    delete [] in; delete [] out; delete [] Y1; delete [] Y2;
}
